class ShoppingCart:
    def __init__(self):
        self.items = []

    def add_item(self, name, price, qty=1):
        self.items.append({'name': name, 'price': price, 'qty': qty})

    def remove_item(self, name):
        self.items = [i for i in self.items if i['name'] != name]

    def get_total(self):
        return sum(i['price'] * i['qty'] for i in self.items)
EOF

