function validateEmail(email) {
  if (!email || email.trim() === '') {
    throw new Error('Email 不得為空');
  }
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!re.test(email)) {
    throw new Error('Email 格式不正確');
  }
  return true;
}
